mapper.insert:
INSERT INTO mcp_protocol_http (
    protocol_id, http_url, http_method, http_headers, timeout, retry_times, status, create_time, update_time
) VALUES (
             #{protocolId}, #{httpUrl}, #{httpMethod}, #{httpHeaders}, #{timeout}, #{retryTimes}, #{status}, NOW(), NOW()
         )

mapper.update:
UPDATE mcp_protocol_http
SET status = #{status}, update_time = NOW()
WHERE protocol_id = #{protocolId}

mapper.select:
SELECT FROM mcp_protocol_http
AND http_url LIKE CONCAT('%', #{urlKeyword}, '%')
ORDER BY id DESC LIMIT #{offset}, #{limit}
